using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Exploration of numbers, structures, and abstract patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Understanding matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Examination of past events and their impact on the present." },
            new() { Id = 6, Name = "Biology", Code = "BIO", Description = "Study of living organisms, their structure, and processes." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a Ph.D. from MIT and has 15 years of experience teaching introductory programming. Her research focuses on CS education and pedagogy.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:00–11:15 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park's research lies at the intersection of algorithm design and machine learning. He previously worked at Google Research." },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS 350", Title = "Database Systems", Description = "Principles of database design, SQL, normalization, transaction management, and an introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Rodriguez", InstructorBio = "Dr. Rodriguez spent a decade in industry at Oracle before joining academia. She specializes in distributed database systems.", IsFeatured = true },

            // Mathematics
            new() { Id = 4, DepartmentId = 2, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Liu", InstructorBio = "An award-winning educator, Dr. Liu has been teaching calculus for over 20 years. He authored the widely used textbook 'Calculus Made Clear'." },
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications in data science and computer graphics.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Nakamura", InstructorBio = "Dr. Nakamura's research covers numerical linear algebra and its applications in scientific computing." },
            new() { Id = 6, DepartmentId = 2, CourseCode = "MATH 310", Title = "Probability and Statistics", Description = "Random variables, probability distributions, hypothesis testing, regression analysis, and Bayesian inference.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM", InstructorName = "Dr. Robert Liu", InstructorBio = "An award-winning educator, Dr. Liu has been teaching calculus for over 20 years. He authored the widely used textbook 'Calculus Made Clear'.", IsFeatured = true },

            // Physics
            new() { Id = 7, DepartmentId = 3, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM + Fri Lab 1:00–3:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an experimental physicist who has published extensively on condensed matter physics." },
            new() { Id = 8, DepartmentId = 3, CourseCode = "PHYS 201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research focuses on quantum optics and photonics. She is a recipient of the National Science Award.", IsFeatured = true },

            // English
            new() { Id = 9, DepartmentId = 4, CourseCode = "ENG 101", Title = "College Writing", Description = "Develop clear, effective academic writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Helen Carter", InstructorBio = "Prof. Carter has an MFA from the Iowa Writers' Workshop and has published two novels and numerous short stories." },
            new() { Id = 10, DepartmentId = 4, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, including Twain, Fitzgerald, Morrison, and more.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is a specialist in 20th-century American fiction and has written extensively on the Harlem Renaissance." },

            // History
            new() { Id = 11, DepartmentId = 5, CourseCode = "HIST 101", Title = "World History to 1500", Description = "A survey of world civilizations from prehistory through the late medieval period, covering Mesopotamia, Rome, China, and the Islamic world.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Karen Whitfield", InstructorBio = "Dr. Whitfield is a medievalist whose work examines cross-cultural exchange along the Silk Road." },
            new() { Id = 12, DepartmentId = 5, CourseCode = "HIST 220", Title = "Modern European History", Description = "Europe from the Enlightenment through the Cold War, with emphasis on political revolutions, industrialization, and world wars.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. David Engel", InstructorBio = "Dr. Engel is an expert in European diplomatic history and a former Fulbright Scholar." },

            // Biology
            new() { Id = 13, DepartmentId = 6, CourseCode = "BIO 101", Title = "Introduction to Biology", Description = "Cell biology, genetics, evolution, and ecology. Includes laboratory component with microscopy and dissection.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Lisa Patel", InstructorBio = "Dr. Patel is a molecular biologist whose research focuses on gene regulation in model organisms.", IsFeatured = true },
            new() { Id = 14, DepartmentId = 6, CourseCode = "BIO 210", Title = "Human Anatomy and Physiology", Description = "Structure and function of the human body systems including skeletal, muscular, nervous, and cardiovascular systems.", Credits = 4, Schedule = "Tue/Thu 8:00–9:15 AM + Wed Lab 1:00–3:50 PM", InstructorName = "Dr. Nathan Cross", InstructorBio = "Dr. Cross is a former surgeon turned educator who brings clinical experience into the classroom." }
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartmentById(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourseById(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

