@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor…"
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name (@dept.Code)</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

@if (filteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in filteredCourses)
            {
                var dept = CatalogService.GetDepartmentById(course.DepartmentId);
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public int? departmentId { get; set; }

    private List<Department> departments = new();
    private List<Course> filteredCourses = new();
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;

    protected override void OnInitialized()
    {
        departments = CatalogService.GetAllDepartments();
        selectedDepartmentId = departmentId ?? 0;
        ApplyFilters();
    }

    private int _selectedDepartmentId;
    private string _searchTerm = string.Empty;

    protected override void OnAfterRender(bool firstRender)
    {
        if (_selectedDepartmentId != selectedDepartmentId || _searchTerm != searchTerm)
        {
            _selectedDepartmentId = selectedDepartmentId;
            _searchTerm = searchTerm;
            ApplyFilters();
            StateHasChanged();
        }
    }

    private void ApplyFilters()
    {
        filteredCourses = CatalogService.SearchCourses(
            searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }

    private void ClearFilters()
    {
        searchTerm = string.Empty;
        selectedDepartmentId = 0;
        ApplyFilters();
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">
        <h4>Course Not Found</h4>
        <p>The requested course does not exist. <a href="courses">Back to catalog</a></p>
    </div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@department?.Id">@department?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><strong>Course Description</strong></div>
                <div class="card-body">
                    <p>@course.Description</p>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header"><strong>Instructor</strong></div>
                <div class="card-body">
                    <h5>@course.InstructorName</h5>
                    <p>@course.InstructorBio</p>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <ul class="list-unstyled">
                        <li class="mb-2"><strong>Department:</strong> @department?.Name</li>
                        <li class="mb-2"><strong>Course Code:</strong> @course.CourseCode</li>
                        <li class="mb-2"><strong>Credits:</strong> @course.Credits</li>
                        <li class="mb-2"><strong>Schedule:</strong> @course.Schedule</li>
                    </ul>
                </div>
            </div>
            <a href="enroll?courseId=@course.Id" class="btn btn-primary w-100">Enroll in This Course</a>
            <a href="courses" class="btn btn-outline-secondary w-100 mt-2">Back to Catalog</a>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;

