+    {
+        departments = CatalogService.GetAllDepartments();
+        selectedDepartmentId = departmentId ?? 0;
+        ApplyFilters();
+    }
+
+    private int _selectedDepartmentId;
+    private string _searchTerm = string.Empty;
+
+    protected override void OnAfterRender(bool firstRender)
+    {
+        if (_selectedDepartmentId != selectedDepartmentId || _searchTerm != searchTerm)
+        {
+            _selectedDepartmentId = selectedDepartmentId;
+            _searchTerm = searchTerm;
+            ApplyFilters();
+            StateHasChanged();
+        }
+    }
+
+    private void ApplyFilters()
+    {
+        filteredCourses = CatalogService.SearchCourses(
+            searchTerm,
+            selectedDepartmentId > 0 ? selectedDepartmentId : null);
+    }
+
+    private void ClearFilters()
+    {
+        searchTerm = string.Empty;
+        selectedDepartmentId = 0;
+        ApplyFilters();
+    }
+}
