@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">
        <h4>Course Not Found</h4>
        <p>The requested course does not exist. <a href="courses">Back to catalog</a></p>
    </div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@department?.Id">@department?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><strong>Course Description</strong></div>
                <div class="card-body">
                    <p>@course.Description</p>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header"><strong>Instructor</strong></div>
                <div class="card-body">
                    <h5>@course.InstructorName</h5>
                    <p>@course.InstructorBio</p>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <ul class="list-unstyled">
                        <li class="mb-2"><strong>Department:</strong> @department?.Name</li>
                        <li class="mb-2"><strong>Course Code:</strong> @course.CourseCode</li>
                        <li class="mb-2"><strong>Credits:</strong> @course.Credits</li>
                        <li class="mb-2"><strong>Schedule:</strong> @course.Schedule</li>
                    </ul>
                </div>
            </div>
            <a href="enroll?courseId=@course.Id" class="btn btn-primary w-100">Enroll in This Course</a>
            <a href="courses" class="btn btn-outline-secondary w-100 mt-2">Back to Catalog</a>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourseById(Id);
        if (course is not null)
            department = CatalogService.GetDepartmentById(course.DepartmentId);
    }
}

