@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our departments, explore course offerings, and submit your enrollment request.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        var dept = CatalogService.GetDepartmentById(course.DepartmentId);
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode — @course.Title</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@dept?.Name · @course.Credits credits</h6>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name <span class="badge bg-secondary">@dept.Code</span></h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-primary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetAllDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

toolArgs.file_text:
@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit an enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@model.FullName</strong>. Your enrollment request for
            <strong>@selectedCourseTitle</strong> has been received. You will be notified once it is processed.</p>
        <a href="enroll" class="btn btn-primary" @onclick="Reset">Submit Another Request</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name</label>
                    <InputText id="fullName" class="form-control" @bind-Value="model.FullName" />
                    <ValidationMessage For="() => model.FullName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="model.StudentId"
                               placeholder="e.g., CS12345" />
                    <ValidationMessage For="() => model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? courseId { get; set; }

    private EnrollmentRequest model = new();
    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();
        if (courseId.HasValue)
            model.CourseId = courseId.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourseById(model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown";
        CatalogService.SubmitEnrollment(model);
        submitted = true;
    }

    private void Reset()
    {
        model = new EnrollmentRequest();
        submitted = false;
    }
}
